import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import HomePage from './components/HomePage';
import PleadingsPage from './components/PleadingsPage';
import MotionsPage from './components/MotionsPage';
import FormsPage from './components/FormsPage';
import ResourcesPage from './components/ResourcesPage';
import ClientForm from './components/ClientForm';
import Login from './components/Login';
import { ThemeProvider } from './context/ThemeContext';

// Protected Route Component
const ProtectedRoute = ({ children }) => {
  const token = localStorage.getItem('token');

  if (!token) {
    return <Navigate to="/login" replace />;
  }

  return children;
};

const DeclarationPage = () => {
  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <Routes>
        <Route
          path="/new"
          element={
            <div className="space-y-6">
              <h2 className="text-2xl font-bold text-gray-900 dark:text-white">
                New Declaration
              </h2>
              <ClientForm />
            </div>
          }
        />
        <Route
          path="/search"
          element={
            <div className="space-y-6">
              <div className="max-w-2xl mx-auto p-6 bg-white dark:bg-gray-800 rounded-lg shadow">
                <input
                  type="search"
                  className="form-input"
                  placeholder="Search declarations..."
                />
              </div>
            </div>
          }
        />
        <Route
          path="/edit"
          element={
            <div className="space-y-6">
              <ClientForm />
            </div>
          }
        />
        <Route
          index
          element={
            <div className="text-center space-y-4">
              <h2 className="text-2xl font-bold text-gray-900 dark:text-white">
                Declaration Management
              </h2>
              <p className="text-gray-600 dark:text-gray-400">
                Please select an option from the menu to continue
              </p>
            </div>
          }
        />
      </Routes>
    </div>
  );
};

function App() {
  return (
    <ThemeProvider>
      <Router>
        <Routes>
          <Route path="/login" element={<Login />} />

          {/* Ruta raíz - siempre redirige al login */}
          <Route 
            path="/" 
            element={<Navigate to="/login" replace />} 
          />

          {/* Rutas protegidas */}
          <Route
            path="/*"
            element={
              <ProtectedRoute>
                <Layout>
                  <Routes>
                    <Route path="/home" element={<HomePage />} />
                    <Route path="/pleadings" element={<PleadingsPage />} />
                    <Route path="/motions" element={<MotionsPage />} />
                    <Route path="/forms" element={<FormsPage />} />
                    <Route path="/resources/*" element={<ResourcesPage />} />
                    <Route path="/declaration/*" element={<DeclarationPage />} />
                  </Routes>
                </Layout>
              </ProtectedRoute>
            }
          />
        </Routes>
      </Router>
    </ThemeProvider>
  );
}

export default App;
